#include <iostream>
#include <deque>

using namespace std;

class Solution {
public:
	bool solve(deque<int>& q) {
		if (q.empty()) return true;
		deque<int> stack;
		while (!q.empty()) {
			int front = q.front();
			q.pop_front();
			if (front == 0) {
				while (!q.empty() && q.front() == 0) {
					q.pop_front();
				}
			} else {
				stack.push_front(front);
			}
			if (stack.empty()) {
				return false;
			}
			q = stack;
			stack.clear();
		}
		return true;
	}
};

int main() {
	// read inputs from cin
	int n; cin >> n;
	deque<int> q;
	for (int i = 0; i < n; ++i) {
		int num; cin >> num;
		q.push_front(num);
	}
	Solution solution;
	cout << (solution.solve(q) ? "true" : "false") << endl;
	return 0;
}
